# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class AccessControlSystem:
    def __init__(self, db_name):
        self.db_name = db_name

    def connect_db(self):
        return sqlite3.connect(self.db_name)

    def check_permission(self, username, file_path):
        conn = self.connect_db()
        cursor = conn.cursor()
        cursor.execute('''
            SELECT permission 
            FROM permissions 
            WHERE username=? AND file_path=?
        ''', (username, file_path))
        result = cursor.fetchone()
        conn.close()
        return result is not None and result[0] == 'read'

    def read_file(self, username, file_path):
        if self.check_permission(username, file_path):
            with open(file_path, 'r') as file:
                return file.read()
        else:
            return "Access Denied: You do not have permission to read this file."

